#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int a[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }
    int max = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            int sum = (a[i] + a[j]) % n;
            if (sum > max) {
                max = sum;
            }
        }
    }
    printf("%d\n", max);
    return 0;
}

