const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let a;
readline.on('line', line => {
    if (!n) {
        n = parseInt(line);
    } else {
        a = line.split(' ').map(num => parseInt(num));
        let max = 0;
        for (let i = 0; i < n; i++) {
            for (let j = i + 1; j < n; j++) {
                let sum = (a[i] + a[j]) % n;
                if (sum > max) {
                    max = sum;
                }
            }
        }
        console.log(max);
        readline.close();
    }
});
